mapper.select:
SELECT E.USER_ID AS USER_ID, E.USER_NO AS USER_NO, E.NAME AS NAME, E.EMAIL AS EMAIL, E.BIRTH_DATE AS BIRTH_DATE, E.ADDRESS_MAIN AS ADDRESS_MAIN, E.ADDRESS_SUB AS ADDRESS_SUB, E.ACTIVE_YN AS ACTIVE_YN, E.CREATED_AT AS CREATED_AT FROM JPAS_TB_USER E WHERE 1=1
AND E.USER_NO LIKE CONCAT('%', #{userNo}, '%')
AND E.NAME LIKE CONCAT('%', #{name}, '%')
AND E.ACTIVE_YN = #{activeYn}
AND E.BIRTH_DATE = #{birthDate}
ORDER BY E.USER_NO
